import{_ as t,o as s,c as o,ae as a}from"./chunks/framework.Baq88w9c.js";const i="/blog-vitepress/assets/ai-tools/chatgpt.webp",r="/blog-vitepress/assets/ai-tools/submagic.jpg",n="/blog-vitepress/assets/ai-tools/microsoft-designer.jpg",l="/blog-vitepress/assets/ai-tools/luma.png",c="/blog-vitepress/assets/ai-tools/soundraw.png",g="/blog-vitepress/assets/ai-tools/v0.png",d="/blog-vitepress/assets/ai-tools/lets-enhance.webp",w=JSON.parse('{"title":"A short list of 7 awesome and free AI tools","description":"","frontmatter":{"title":"A short list of 7 awesome and free AI tools","date":"2024-06-20T00:00:00.000Z"},"headers":[],"relativePath":"posts/awesome-ai-tools.md","filePath":"posts/awesome-ai-tools.md"}'),h={name:"posts/awesome-ai-tools.md"};function u(m,e,p,f,b,y){return s(),o("div",null,[...e[0]||(e[0]=[a('<p>Many AI tools have emerged in the past 2 years. I&#39;ve tried a few of them and made a short list of those I found the most useful.</p><ul><li><img width="30" height="30" src="'+i+'" alt="" loading="lazy" decoding="async"> <a href="https://chat.openai.com/chat" target="_blank" rel="noreferrer">ChatGPT</a> is one of the most useful AI tools that is publicly available (and it&#39;s free too!). It&#39;s use cases range from generating answers to specific code problems, creating ideas for blog posts, getting quick (though not reliable) answers to legal issues, to writing jokes or generating alternative endings to your favorite stories. It has a huge amount of many different kinds of use cases, many yet undiscovered.</li><li><img width="30" height="30" src="'+r+'" alt="" loading="lazy" decoding="async"> <a href="https://www.submagic.co/" target="_blank" rel="noreferrer">Submagic</a> is a helpful tool that can automatically add captions to videos using AI. The tool supports many different languages and can be used to quickly add subtitles to short videos for your business social media (like YouTube Shorts, TikTok). Submagic also provides other simple to use video enhancement features like adding background music, transitions, auto-cutting silent parts of the video.</li><li><img width="30" height="30" src="'+n+'" alt="" loading="lazy" decoding="async"> <a href="https://www.bing.com/images/create?FORM=GENEXP" target="_blank" rel="noreferrer">Microsoft Designer</a> is a neat tool for generating images with 15 free daily generations. Each generation produces up to 4 different results. This tool has many different use cases - creating artwork, posters, advertisement ideas, Slack avatars, book covers, brand logos.</li><li><img width="30" height="30" src="'+l+'" alt="" loading="lazy" decoding="async"> <a href="https://lumalabs.ai/genie/" target="_blank" rel="noreferrer">Luma AI - Genie</a> is a free tool for generating 3D meshes with textures which can be quite useful for 3D game prototyping. Similarly to Microsoft Designer, Genie generates up to 4 versions for each prompt.</li><li><img width="30" height="30" src="'+c+'" alt="" loading="lazy" decoding="async"> <a href="https://soundraw.io/" target="_blank" rel="noreferrer">Soundraw</a> is an impressive tool for generating music which can be used for games, videos, and anything you want. You can choose the music&#39;s theme, genre, mood. The generated soundtracks are also customizable - each instrument&#39;s loudness is controllable and you can change the track&#39;s BPM.</li><li><img width="30" height="30" src="'+g+'" alt="" loading="lazy" decoding="async"> <a href="https://v0.dev/" target="_blank" rel="noreferrer">V0</a> is a free tool by Vercel for generating websites from text prompts. The tool currently supports vanilla HTML and React as output formats. It can be especially useful for generating layout ideas if your head feels empty at the moment. Generated layouts can be continuously improved by adding more prompts like &quot;change red color to orange&quot;, &quot;use mono font&quot;.</li><li><img width="30" height="30" src="'+d+'" alt="" loading="lazy" decoding="async"> <a href="https://letsenhance.io/" target="_blank" rel="noreferrer">Let&#39;s Enhance</a> is a very useful tool for upscaling images. It can be used in conjunction with Microsoft Designer to generate high quality images from a text input. It can produce images in 4K and beyond which is very valuable for generating high quality desktop wallpapers or large printable pictures.</li></ul>',2)])])}const v=t(h,[["render",u]]);export{w as __pageData,v as default};
